function ensureCompiledReportViews() {
  const allowed = new Set(getAllCompiledReportViews());
  const current = Array.isArray(state.compiledReportIncludedViews) ? state.compiledReportIncludedViews.filter((view) => allowed.has(view)) : [];
  state.compiledReportIncludedViews = current.length > 0 ? current : getAllCompiledReportViews();
}

function loadOutputWorkspaceState() {
  if (!state.selectedProjectId) {
    state.compiledReportStyleTemplate = 'classic';
    state.outputPivotProfiles = {};
    state.outputPivotLayouts = {};
    state.outputChartPresets = {};
    state.outputChartBuilderState = {
      chartType: 'bar',
      palette: 'sand',
      showDataLabels: true,
      showTrendLine: false,
      useLogScale: false,
      xColumn: -1,
      yColumn: -1,
      title: '',
      subtitle: ''
    };
    return;
  }
  try {
    const raw = window.localStorage.getItem(OUTPUT_WORKSPACE_STATE_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    const scoped = parsed?.[state.selectedProjectId] ?? {};
    state.compiledReportStyleTemplate = getOutputStyleTemplateDefinition(scoped.styleTemplate)?.key ?? 'classic';
    state.outputPivotProfiles = scoped.outputPivotProfiles && typeof scoped.outputPivotProfiles === 'object' ? scoped.outputPivotProfiles : {};
    state.outputPivotLayouts = scoped.outputPivotLayouts && typeof scoped.outputPivotLayouts === 'object' ? scoped.outputPivotLayouts : {};
    state.outputChartPresets = scoped.outputChartPresets && typeof scoped.outputChartPresets === 'object' ? scoped.outputChartPresets : {};
    state.outputChartBuilderState = {
      chartType: 'bar',
      palette: 'sand',
      showDataLabels: true,
      showTrendLine: false,
      useLogScale: false,
      xColumn: -1,
      yColumn: -1,
      title: '',
      subtitle: '',
      ...(scoped.outputChartBuilderState && typeof scoped.outputChartBuilderState === 'object' ? scoped.outputChartBuilderState : {})
    };
    if (Array.isArray(scoped.compiledReportIncludedViews) && scoped.compiledReportIncludedViews.length > 0) {
      state.compiledReportIncludedViews = scoped.compiledReportIncludedViews;
    }
  } catch {
    state.compiledReportStyleTemplate = 'classic';
    state.outputPivotProfiles = {};
    state.outputPivotLayouts = {};
    state.outputChartPresets = {};
  }
}

function persistOutputWorkspaceState() {
  if (!state.selectedProjectId) return;
  try {
    const raw = window.localStorage.getItem(OUTPUT_WORKSPACE_STATE_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    parsed[state.selectedProjectId] = {
      styleTemplate: getOutputStyleTemplateDefinition().key,
      outputPivotProfiles: state.outputPivotProfiles,
      outputPivotLayouts: state.outputPivotLayouts,
      outputChartBuilderState: state.outputChartBuilderState,
      outputChartPresets: state.outputChartPresets,
      compiledReportIncludedViews: state.compiledReportIncludedViews
    };
    window.localStorage.setItem(OUTPUT_WORKSPACE_STATE_STORAGE_KEY, JSON.stringify(parsed));
  } catch {
    // Ignore localStorage failures in the browser shell.
  }
}

function loadOutputPacks() {
  if (!state.selectedProjectId) {
    state.outputPacks = [];
    return;
  }
  try {
    const raw = window.localStorage.getItem(OUTPUT_PACKS_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    state.outputPacks = Array.isArray(parsed?.[state.selectedProjectId]) ? parsed[state.selectedProjectId] : [];
  } catch {
    state.outputPacks = [];
  }
}

function persistOutputPacks() {
  if (!state.selectedProjectId) return;
  try {
    const raw = window.localStorage.getItem(OUTPUT_PACKS_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    parsed[state.selectedProjectId] = state.outputPacks;
    window.localStorage.setItem(OUTPUT_PACKS_STORAGE_KEY, JSON.stringify(parsed));
  } catch {
    // Ignore localStorage failures in the browser shell.
  }
}

function buildOutputPackPayload(label = '') {
  return {
    id: `output-pack-${Date.now()}`,
    label: String(label || 'Output pack').trim(),
    version: 1,
    generatedAt: new Date().toISOString(),
    projectId: state.selectedProjectId ?? null,
    projectName: state.selectedSummary?.project?.name ?? '',
    styleTemplate: getOutputStyleTemplateDefinition().key,
    quantOutputView: state.quantOutputView,
    quantOutputTreeSelection: state.quantOutputTreeSelection,
    quantOutputTreeOpenGroups: cloneJson(state.quantOutputTreeOpenGroups),
    compiledReportIncludedViews: cloneJson(state.compiledReportIncludedViews),
    outputPivotProfiles: cloneJson(state.outputPivotProfiles),
    outputPivotLayouts: cloneJson(state.outputPivotLayouts),
    outputChartBuilderState: cloneJson(state.outputChartBuilderState),
    outputChartPresets: cloneJson(state.outputChartPresets),
    quantOutputHistory: cloneJson(state.quantOutputHistory)
  };
}

function applyOutputPack(pack, options = {}) {
  if (!pack || typeof pack !== 'object') throw new Error('Invalid output pack payload.');
  const targetProject = String(pack.projectId ?? '').trim();
  if (targetProject && state.selectedProjectId && targetProject !== state.selectedProjectId) {
    const proceed = window.confirm(`This pack is for project ${targetProject}. Apply anyway?`);
    if (!proceed) return false;
  }
  state.compiledReportStyleTemplate = getOutputStyleTemplateDefinition(pack.styleTemplate)?.key ?? 'classic';
  state.quantOutputView = String(pack.quantOutputView || state.quantOutputView || 'descriptives');
  state.quantOutputTreeSelection = String(pack.quantOutputTreeSelection || '');
  state.quantOutputTreeOpenGroups = {
    live: true,
    history: true,
    saved: true,
    ...(pack.quantOutputTreeOpenGroups && typeof pack.quantOutputTreeOpenGroups === 'object' ? pack.quantOutputTreeOpenGroups : {})
  };
  state.compiledReportIncludedViews = Array.isArray(pack.compiledReportIncludedViews)
    ? pack.compiledReportIncludedViews
    : getAllCompiledReportViews();
  state.outputPivotProfiles = pack.outputPivotProfiles && typeof pack.outputPivotProfiles === 'object' ? pack.outputPivotProfiles : {};
  state.outputPivotLayouts = pack.outputPivotLayouts && typeof pack.outputPivotLayouts === 'object' ? pack.outputPivotLayouts : {};
  state.outputChartBuilderState = {
    chartType: 'bar',
    palette: 'sand',
    showDataLabels: true,
    showTrendLine: false,
    useLogScale: false,
    xColumn: -1,
    yColumn: -1,
    title: '',
    subtitle: '',
    ...(pack.outputChartBuilderState && typeof pack.outputChartBuilderState === 'object' ? pack.outputChartBuilderState : {})
  };
  state.outputChartPresets = pack.outputChartPresets && typeof pack.outputChartPresets === 'object' ? pack.outputChartPresets : {};
  if (Array.isArray(pack.quantOutputHistory) && pack.quantOutputHistory.length > 0) {
    state.quantOutputHistory = pack.quantOutputHistory.slice(0, 24);
  }
  ensureCompiledReportViews();
  applyOutputStyleTemplateToWorkspace();
  persistOutputWorkspaceState();
  renderAll();
  return true;
}

function exportOutputPackJson(pack) {
  requireProjectExportPermission();
  const payload = cloneJson(pack ?? buildOutputPackPayload('Output pack'));
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  const labelToken = normalizeAnalysisFieldKey(payload.label || 'output-pack');
  anchor.download = `${state.selectedProjectId ?? 'muStatistics'}-${labelToken || 'output-pack'}.json`;
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(url);
}

function renderOutputPackList() {
  const node = document.getElementById('output-pack-list');
  if (!node) return;
  if (!state.selectedProjectId || state.outputPacks.length === 0) {
    node.innerHTML = '<li class="interactive-list-item empty">No output packs saved for this project yet.</li>';
    return;
  }
  node.innerHTML = '';
  for (const pack of state.outputPacks) {
    const li = document.createElement('li');
    li.className = 'interactive-list-item';
    li.innerHTML = `
      <div class="compiled-report-preset-row">
        <div class="compiled-report-preset-meta">
          <span class="workspace-meta">Output pack v${escapeHtml(String(pack.version ?? 1))}</span>
          <span class="project-title">${escapeHtml(String(pack.label ?? 'Output pack'))}</span>
          <span class="source-meta">${escapeHtml(new Date(pack.generatedAt || Date.now()).toLocaleString())}</span>
        </div>
        <div class="compiled-report-preset-actions">
          <button type="button" class="small output-pack-apply-btn">Apply</button>
          <button type="button" class="small output-pack-open-btn">Open report</button>
          <button type="button" class="small output-pack-export-btn">JSON</button>
          <button type="button" class="small danger output-pack-delete-btn">Delete</button>
        </div>
      </div>
    `;
    li.querySelector('.output-pack-apply-btn')?.addEventListener('click', () => {
      try {
        applyOutputPack(pack);
      } catch (err) {
        window.alert(`Output pack apply failed: ${err.message}`);
      }
    });
    li.querySelector('.output-pack-open-btn')?.addEventListener('click', () => {
      try {
        if (applyOutputPack(pack)) openCompiledReportWindow();
      } catch (err) {
        window.alert(`Output pack open failed: ${err.message}`);
      }
    });
    li.querySelector('.output-pack-export-btn')?.addEventListener('click', () => {
      try {
        exportOutputPackJson(pack);
      } catch (err) {
        window.alert(`Output pack export failed: ${err.message}`);
      }
    });
    li.querySelector('.output-pack-delete-btn')?.addEventListener('click', () => {
      state.outputPacks = state.outputPacks.filter((entry) => entry.id !== pack.id);
      persistOutputPacks();
      renderOutputPackList();
    });
    node.appendChild(li);
  }
}

function loadCompiledReportPresets() {
  try {
    const raw = window.localStorage.getItem(COMPILED_REPORT_PRESETS_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    const items = Array.isArray(parsed?.[state.selectedProjectId]) ? parsed[state.selectedProjectId] : [];
    state.compiledReportPresets = items.map((item) => ({
      ...item,
      favorite: Boolean(item?.favorite),
      views: Array.isArray(item?.views) ? item.views : getAllCompiledReportViews()
    }));
  } catch {
    state.compiledReportPresets = [];
  }
}

function persistCompiledReportPresets() {
  try {
    const raw = window.localStorage.getItem(COMPILED_REPORT_PRESETS_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    parsed[state.selectedProjectId] = state.compiledReportPresets;
    window.localStorage.setItem(COMPILED_REPORT_PRESETS_STORAGE_KEY, JSON.stringify(parsed));
  } catch {
    // Ignore localStorage failures in the browser shell.
  }
}

function getCompiledReportSections() {
  ensureCompiledReportViews();
  const sections = [];
  const seen = new Set();
  const orderedViews = state.compiledReportIncludedViews.filter((view) => {
    if (seen.has(view)) return false;
    seen.add(view);
    return state.compiledReportIncludedViews.includes(view);
  });

  for (const view of orderedViews) {
    const panel = document.querySelector(`[data-quant-output="${view}"]`);
    if (!panel) continue;
    const html = panel.innerHTML.trim();
    if (!html) continue;
    sections.push({
      view,
      title: quantOutputTitle(view),
      html
    });
  }

  return sections;
}

function buildCompiledReportHtml() {
  const projectName = state.selectedSummary?.project?.name ?? 'muStatistics project';
  const generatedAt = new Date().toLocaleString();
  const sections = getCompiledReportSections();
  const style = getOutputStyleTemplateDefinition();
  const documentTree = state.quantOutputDocumentTree ?? buildQuantOutputDocumentTree();
  const nodeCount = (documentTree.groups ?? []).reduce(
    (total, group) => total + (group.sections ?? []).reduce((sum, section) => sum + (section.items?.length ?? 0), 0),
    0
  );
  const historyItems = state.quantOutputHistory.map((entry) => `
    <li><span>${escapeHtml(entry.title)}</span><span>${escapeHtml(entry.stamp)}</span></li>
  `).join('');

  return `<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <title>${escapeHtml(projectName)} report stack</title>
    <style>
      :root {
        color-scheme: light;
        --paper:${escapeHtml(style.paper)};
        --ink:${escapeHtml(style.ink)};
        --muted:${escapeHtml(style.muted)};
        --line:${escapeHtml(style.line)};
        --accent:${escapeHtml(style.accent)};
      }
      * { box-sizing:border-box; }
      body {
        margin:0;
        padding:32px;
        font-family: ${escapeHtml(style.bodyFont)};
        color:var(--ink);
        background:var(--paper);
      }
      .report-shell { display:grid; gap:28px; }
      .cover, .index, .section {
        background:#fff;
        border:1px solid var(--line);
        border-radius:${escapeHtml(style.sectionRadius)};
        padding:${escapeHtml(style.sectionPadding)};
        page-break-inside: avoid;
      }
      .cover h1, .section h2 {
        margin:6px 0 0;
        font-family: ${escapeHtml(style.headingFont)};
      }
      .kicker {
        color:var(--accent);
        text-transform:uppercase;
        letter-spacing:.08em;
        font-size:12px;
      }
      .meta {
        display:flex;
        justify-content:space-between;
        gap:16px;
        flex-wrap:wrap;
        color:var(--muted);
        font-size:13px;
        margin-top:18px;
        padding-top:14px;
        border-top:1px solid var(--line);
      }
      .index ol, .history ol { margin:14px 0 0; padding-left:18px; }
      .index li, .history li {
        display:flex;
        justify-content:space-between;
        gap:12px;
        padding:8px 0;
        border-bottom:1px solid #eee;
      }
      .section-head {
        display:flex;
        justify-content:space-between;
        align-items:flex-start;
        gap:20px;
        margin-bottom:18px;
        padding-bottom:14px;
        border-bottom:1px solid var(--line);
      }
      .section-body { display:grid; gap:16px; }
      .section-body .inline-actions, .section-body button { display:none !important; }
      .section-body .output-viewer, .section-body .saved-analysis-cover-sheet, .section-body .saved-analysis-index, .section-body .saved-analysis-entry {
        border:none !important;
        background:transparent !important;
        box-shadow:none !important;
        padding-left:0 !important;
        padding-right:0 !important;
      }
      .section-body .output-document-bar, .section-body .output-footer { display:none !important; }
      .section-body .matrix-table-wrap { border-color:var(--line) !important; background:transparent !important; }
      .section-body .matrix-table th { background:#f5f1e8 !important; color:var(--ink) !important; }
      @media print {
        body { padding:0; background:#fff; }
        .cover, .index, .section { border:none; border-radius:0; page-break-after:always; }
      }
    </style>
  </head>
  <body>
    <div class="report-shell">
      <section class="cover">
        <span class="kicker">Compiled report</span>
        <h1>${escapeHtml(projectName)}</h1>
        <p>Saved analysis stack, current output pages, and recent viewer history assembled into one report document.</p>
        <div class="meta">
          <span>Generated ${escapeHtml(generatedAt)}</span>
          <span>Template ${escapeHtml(style.label)}</span>
          <span>Tree nodes ${nodeCount}</span>
          <span>Sections ${sections.length}</span>
        </div>
      </section>
      <section class="index">
        <span class="kicker">Index</span>
        <h2>Report sections</h2>
        <ol>
          ${sections.map((section, index) => `<li><span>${index + 1}. ${escapeHtml(section.title)}</span><span>${escapeHtml(section.view)}</span></li>`).join('')}
        </ol>
      </section>
      <section class="index history">
        <span class="kicker">Appendix</span>
        <h2>Recent output history</h2>
        <ol>
          ${historyItems || '<li><span>No recent output</span><span></span></li>'}
        </ol>
      </section>
      ${sections.map((section, index) => `
        <section class="section">
          <div class="section-head">
            <div>
              <span class="kicker">Section ${index + 1}</span>
              <h2>${escapeHtml(section.title)}</h2>
            </div>
            <span class="kicker">${escapeHtml(section.view)}</span>
          </div>
          <div class="section-body">${section.html}</div>
        </section>
      `).join('')}
    </div>
  </body>
</html>`;
}

function openCompiledReportWindow() {
  requireProjectExportPermission();
  const reportWindow = window.open('', 'muStatisticsCompiledReport', 'width=1200,height=900');
  if (!reportWindow) throw new Error('Popup blocked while opening compiled report.');
  reportWindow.document.open();
  reportWindow.document.write(buildCompiledReportHtml());
  reportWindow.document.close();
  reportWindow.focus();
}

function exportCompiledReportHtml() {
  requireProjectExportPermission();
  const blob = new Blob([buildCompiledReportHtml()], { type: 'text/html;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = `${state.selectedProjectId ?? 'muStatistics'}-${getOutputStyleTemplateDefinition().key}-compiled-report.html`;
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(url);
}

function renderCompiledReportControls() {
  const node = document.getElementById('compiled-report-controls');
  if (!node) return;
  ensureCompiledReportViews();
  const included = [...state.compiledReportIncludedViews];
  const excluded = getAllCompiledReportViews().filter((view) => !included.includes(view));
  const orderedViews = [...included, ...excluded];
  node.innerHTML = orderedViews.map((view) => {
    const includedIndex = included.indexOf(view);
    const isIncluded = includedIndex >= 0;
    return `
      <label class="report-include-option${isIncluded ? ' included' : ''}" ${isIncluded ? `draggable="true" data-report-draggable="${escapeHtml(view)}"` : ''}>
        <span class="report-include-main">
          <input type="checkbox" data-report-include="${escapeHtml(view)}" ${isIncluded ? 'checked' : ''} />
          <span>${escapeHtml(quantOutputTitle(view))}</span>
        </span>
        ${isIncluded ? `
          <span class="report-order-controls">
            <button type="button" class="small" data-report-move="${escapeHtml(view)}" data-report-direction="up" ${includedIndex === 0 ? 'disabled' : ''}>Up</button>
            <button type="button" class="small" data-report-move="${escapeHtml(view)}" data-report-direction="down" ${includedIndex === included.length - 1 ? 'disabled' : ''}>Down</button>
          </span>
        ` : '<span class="small-muted">Excluded</span>'}
      </label>
    `;
  }).join('');
  node.querySelectorAll('[data-report-include]').forEach((input) => {
    input.addEventListener('change', () => {
      const checked = [...node.querySelectorAll('[data-report-include]:checked')].map((entry) => entry.dataset.reportInclude);
      state.compiledReportIncludedViews = checked.length > 0 ? checked : getAllCompiledReportViews();
      persistOutputWorkspaceState();
      renderCompiledReportControls();
    });
  });
  node.querySelectorAll('[data-report-move]').forEach((button) => {
    button.addEventListener('click', () => {
      const view = button.dataset.reportMove;
      const direction = button.dataset.reportDirection;
      const index = state.compiledReportIncludedViews.indexOf(view);
      if (index < 0) return;
      const targetIndex = direction === 'up' ? index - 1 : index + 1;
      if (targetIndex < 0 || targetIndex >= state.compiledReportIncludedViews.length) return;
      const reordered = [...state.compiledReportIncludedViews];
      [reordered[index], reordered[targetIndex]] = [reordered[targetIndex], reordered[index]];
      state.compiledReportIncludedViews = reordered;
      persistOutputWorkspaceState();
      renderCompiledReportControls();
    });
  });
  node.querySelectorAll('[data-report-draggable]').forEach((row) => {
    row.addEventListener('dragstart', (event) => {
      event.dataTransfer?.setData('text/plain', row.dataset.reportDraggable ?? '');
      event.dataTransfer.effectAllowed = 'move';
      row.classList.add('dragging');
    });
    row.addEventListener('dragend', () => {
      row.classList.remove('dragging');
    });
    row.addEventListener('dragover', (event) => {
      event.preventDefault();
      event.dataTransfer.dropEffect = 'move';
    });
    row.addEventListener('drop', (event) => {
      event.preventDefault();
      const draggedView = event.dataTransfer?.getData('text/plain');
      const targetView = row.dataset.reportDraggable;
      if (!draggedView || !targetView || draggedView === targetView) return;
      const reordered = state.compiledReportIncludedViews.filter((view) => view !== draggedView);
      const targetIndex = reordered.indexOf(targetView);
      if (targetIndex < 0) return;
      reordered.splice(targetIndex, 0, draggedView);
      state.compiledReportIncludedViews = reordered;
      persistOutputWorkspaceState();
      renderCompiledReportControls();
    });
  });
}

function renderCompiledReportPresets() {
  const node = document.getElementById('compiled-report-presets-list');
  if (!node) return;
  node.classList.add('compiled-report-presets');
  if (!state.selectedProjectId || state.compiledReportPresets.length === 0) {
    node.innerHTML = '<li class="interactive-list-item empty">No report presets saved for this project yet.</li>';
    return;
  }

  node.innerHTML = '';
  const orderedPresets = [...state.compiledReportPresets].sort((left, right) => {
    if (Boolean(left.favorite) !== Boolean(right.favorite)) return left.favorite ? -1 : 1;
    return String(left.label ?? '').localeCompare(String(right.label ?? ''));
  });
  let currentGroup = '';
  for (const preset of orderedPresets) {
    const group = preset.favorite ? 'Pinned packs' : 'Other presets';
    if (group !== currentGroup) {
      currentGroup = group;
      const groupRow = document.createElement('li');
      groupRow.className = 'interactive-list-item compiled-report-group';
      groupRow.innerHTML = `<strong>${escapeHtml(group)}</strong>`;
      node.appendChild(groupRow);
    }
    const li = document.createElement('li');
    li.className = `interactive-list-item${preset.favorite ? ' is-favorite' : ''}`;
    li.innerHTML = `
      <div class="compiled-report-preset-row">
        <div class="compiled-report-preset-meta">
          <span class="workspace-meta">${preset.favorite ? 'Pinned pack' : 'Reusable preset'}</span>
          <span class="project-title">${escapeHtml(preset.label)}</span>
          <span class="source-meta">${preset.views.map((view) => escapeHtml(quantOutputTitle(view))).join(' | ')}</span>
        </div>
        <div class="compiled-report-preset-actions">
          <button type="button" class="small report-preset-favorite-btn">${preset.favorite ? 'Unpin' : 'Pin'}</button>
          <button type="button" class="small report-preset-apply-btn">Apply</button>
          <button type="button" class="small report-preset-open-btn">Open</button>
          <button type="button" class="small report-preset-export-btn">HTML</button>
          <button type="button" class="small report-preset-rename-btn">Rename</button>
          <button type="button" class="small report-preset-duplicate-btn">Duplicate</button>
          <button type="button" class="small danger report-preset-delete-btn">Delete</button>
        </div>
      </div>
    `;
    const applyPreset = () => {
      state.compiledReportIncludedViews = Array.isArray(preset.views) && preset.views.length > 0 ? preset.views : getAllCompiledReportViews();
      persistOutputWorkspaceState();
      renderCompiledReportControls();
    };
    li.querySelector('.report-preset-favorite-btn')?.addEventListener('click', () => {
      state.compiledReportPresets = state.compiledReportPresets.map((entry) =>
        entry.id === preset.id ? { ...entry, favorite: !entry.favorite } : entry
      );
      persistCompiledReportPresets();
      renderCompiledReportPresets();
    });
    li.querySelector('.report-preset-apply-btn')?.addEventListener('click', applyPreset);
    li.querySelector('.report-preset-open-btn')?.addEventListener('click', () => {
      applyPreset();
      openCompiledReportWindow();
    });
    li.querySelector('.report-preset-export-btn')?.addEventListener('click', () => {
      applyPreset();
      exportCompiledReportHtml();
    });
    li.querySelector('.report-preset-rename-btn')?.addEventListener('click', () => {
      const nextLabel = window.prompt('Rename report preset', preset.label)?.trim();
      if (!nextLabel) return;
      state.compiledReportPresets = state.compiledReportPresets.map((entry) =>
        entry.id === preset.id ? { ...entry, label: nextLabel } : entry
      );
      persistCompiledReportPresets();
      renderCompiledReportPresets();
    });
    li.querySelector('.report-preset-duplicate-btn')?.addEventListener('click', () => {
      const duplicateLabel = window.prompt('Duplicate report preset as', `${preset.label} copy`)?.trim();
      if (!duplicateLabel) return;
      state.compiledReportPresets = [
        {
          id: `preset-${Date.now()}`,
          label: duplicateLabel,
          views: [...(preset.views ?? [])],
          favorite: Boolean(preset.favorite)
        },
        ...state.compiledReportPresets
      ].slice(0, 20);
      persistCompiledReportPresets();
      renderCompiledReportPresets();
    });
    li.querySelector('.report-preset-delete-btn')?.addEventListener('click', () => {
      state.compiledReportPresets = state.compiledReportPresets.filter((entry) => entry.id !== preset.id);
      persistCompiledReportPresets();
      renderCompiledReportPresets();
    });
    node.appendChild(li);
  }
}

function renderOutputStyleTemplateControls() {
  const select = document.getElementById('output-style-template-select');
  if (!select) return;
  const currentKey = getOutputStyleTemplateDefinition().key;
  select.innerHTML = Object.values(OUTPUT_STYLE_TEMPLATES)
    .map((template) => `<option value="${escapeHtml(template.key)}" ${template.key === currentKey ? 'selected' : ''}>${escapeHtml(template.label)}</option>`)
    .join('');
}

function getWorkspaceSelection(container, baseStart = 0) {
  if (!container) return null;
  const selection = window.getSelection();
  if (!selection || selection.rangeCount === 0 || selection.isCollapsed) return null;
  const range = selection.getRangeAt(0);
  if (!container.contains(range.startContainer) || !container.contains(range.endContainer)) return null;
  const startRange = range.cloneRange();
  startRange.selectNodeContents(container);
  startRange.setEnd(range.startContainer, range.startOffset);
  const endRange = range.cloneRange();
  endRange.selectNodeContents(container);
  endRange.setEnd(range.endContainer, range.endOffset);
  const start = startRange.toString().length;
  const end = endRange.toString().length;
  const text = range.toString();
  if (!text.trim() || end <= start) return null;
  return {
    start,
    end,
    absoluteStart: baseStart + start,
    absoluteEnd: baseStart + end,
    text
  };
}

function setAriaCurrent(button, isActive) {
  if (!(button instanceof HTMLElement)) return;
  if (isActive) {
    button.setAttribute('aria-current', 'page');
  } else {
    button.removeAttribute('aria-current');
  }
}

