          data-end-ms="${escapeHtml(String(bin.endMs))}"
          title="${escapeHtml(`${formatMediaClock(bin.startMs)}-${formatMediaClock(bin.endMs)} | segments ${bin.segmentCount} | sync ${bin.syncLinkCount}`)}"
